import React from 'react';
import LiveTicker from '../components/LiveTicker';
import AssetCard from '../components/AssetCard';

// Resimleri içeri aktarıyoruz
import pirlantaImg from '../assets/images/pirlanta.jpg';
import bilezikImg from '../assets/images/bilezik.jpg';
import gramImg from '../assets/images/gram.jpg';

const Home = () => {
    return (
        <div className="home-container">
            <LiveTicker />

            <div className="hero-section" style={{ padding: '60px 20px' }}>
                <h1 className="hero-title" style={{ fontSize: '3.5rem', marginBottom: '15px' }}>
                    <span className="gold-text">AURUM</span> X Özel Koleksiyonu
                </h1>
                <p className="hero-subtitle" style={{ color: '#a0a0a0', fontSize: '1.2rem', maxWidth: '600px', margin: '0 auto 50px auto' }}>
                    Geleneksel zanaat ile yenilikçi teknolojinin buluştuğu eşsiz mücevher vitrinimize hoş geldiniz.
                </p>

                <div className="catalog" style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', gap: '30px' }}>
                    <AssetCard 
                        image={pirlantaImg} 
                        title="Pırlanta Tektaş Yüzük" 
                        type="Fiziksel Mücevher" 
                        price="₺45.000" 
                    />
                    <AssetCard 
                        image={bilezikImg} 
                        title="22 Ayar Burma Bilezik" 
                        type="Fiziksel Mücevher" 
                        price="₺28.500" 
                    />
                    <AssetCard 
                        image={gramImg} 
                        title="Gram Altın Sertifikası" 
                        type="Dijital Varlık" 
                        price="₺2.150" 
                    />
                </div>
            </div>
        </div>
    );
};

export default Home;
